"use client";

import React, { useState } from "react";
import { cn } from "@/lib/cn";

interface TabsProps {
  children: React.ReactNode;
  defaultValue?: string;
  className?: string;
}

export function Tabs({ children, defaultValue, className = "" }: TabsProps) {
  const [active, setActive] = useState(defaultValue || "");
  return (
    <div data-active={active} className={cn(className)}>
      {children
        ? React.Children.map(children, (child) =>
            React.isValidElement(child)
              ? React.cloneElement(child as React.ReactElement<Record<string, unknown>>, {
                  active,
                  onChange: setActive,
                })
              : child,
          )
        : null}
    </div>
  );
}

interface TabsListProps {
  children: React.ReactNode;
  variant?: "default" | "underline";
  className?: string;
  active?: string;
  onChange?: (value: string) => void;
}

export function TabsList({
  children,
  variant = "default",
  className = "",
  active,
  onChange,
}: TabsListProps) {
  return (
    <div
      className={cn(
        "flex gap-0",
        variant === "underline" && "border-b border-[var(--border)]",
        variant === "default" && "rounded-[3px] bg-[var(--surface-alt)] p-1",
        className,
      )}
    >
      {typeof children === "object"
        ? React.Children.map(children, (child) =>
            React.isValidElement(child)
              ? React.cloneElement(child as React.ReactElement<Record<string, unknown>>, {
                  active,
                  onChange,
                  variant,
                })
              : child,
          )
        : children}
    </div>
  );
}

interface TabsTabProps {
  children: React.ReactNode;
  value: string;
  className?: string;
  active?: string;
  onChange?: (value: string) => void;
  variant?: "default" | "underline";
}

export function TabsTab({
  children,
  value,
  className = "",
  active,
  onChange,
  variant = "default",
}: TabsTabProps) {
  const isActive = active === value;
  return (
    <button
      type="button"
      onClick={() => onChange?.(value)}
      className={cn(
        "relative cursor-pointer bg-transparent px-6 py-3 text-[14px] font-medium transition-colors duration-200",
        isActive
          ? "text-[var(--foreground)]"
          : "text-[var(--foreground-subtle)] hover:text-[var(--foreground)]",
        className,
      )}
    >
      {children}
      {variant === "underline" && (
        <span
          className={cn(
            "absolute right-0 bottom-0 left-0 h-0.5 bg-[var(--blue)] transition-transform duration-300",
            isActive ? "scale-x-100" : "scale-x-0",
          )}
          style={{ transformOrigin: "center" }}
        />
      )}
    </button>
  );
}

interface TabsPanelProps {
  children: React.ReactNode;
  value: string;
  className?: string;
  active?: string;
}

export function TabsPanel({
  children,
  value,
  className = "",
  active,
}: TabsPanelProps) {
  if (active !== value) return null;
  return <div className={cn(className)}>{children}</div>;
}

export type { TabsProps, TabsListProps, TabsTabProps, TabsPanelProps };
